import random
import time

def clear_terminal():
    print('\033[2J\033[H', end='')

print("Welcome to Royal Favors. Your goal is to satisfy your lord's demands.")

favors = ["Grant a title", "Bestow wealth upon my family", "Provide a noble steed"]
unsatisfiable_demands = ["Rescue the kidnapped princess", "Revenge against my sworn enemy"]

while True:
    clear_terminal()
    print("Your current favors:")
    for favor in favors:
        if random.random() < 0.5: # 50% chance of being granted
            print(f" + {favor}")
    print()

    action = input("Do you wish to grant a new favor or check the unsatisfiable demands? (g/c): ")

    if action.lower() == 'g':
        clear_terminal()
        print("Choose a new favor:")
        for i, favor in enumerate(favors):
            print(f"{i+1}. {favor}")
        choice = int(input("Enter the number of the favor: "))
        favors[choice-1] = random.choice(unsatisfiable_demands) # Replace with satisfaction option
    elif action.lower() == 'c':
        clear_terminal()
        if all(random.random() < 0.9 for _ in unsatisfiable_demands): # Check if all demands are satisfied
            print("All unsatisfiable demands have been met.")
            break

time.sleep(1) # Add a short delay to make the game more engaging